package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserParseFileTest {

    private File mockFile;
    private CSVFormat mockFormat;
    private FileReader mockFileReader;

    @BeforeEach
    void setup() {
        mockFile = mock(File.class);
        mockFormat = mock(CSVFormat.class);
        mockFileReader = mock(FileReader.class);
    }

    @Test
    void parse_NullFile_ThrowsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((File) null, mockFormat);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockFile, null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void parse_ValidFileAndFormat_ReturnsCSVParser() throws IOException {
        // Since Mockito 3 does not have mockConstruction, we mock FileReader and spy CSVParser constructor call
        // Instead, we can spy CSVParser and stub constructor indirectly by using partial mocking or a wrapper
        // But here, simplest is to mock FileReader and then call CSVParser constructor directly

        // Mock FileReader constructor by spying on CSVParser constructor with our mockFileReader
        CSVParser parser = new CSVParser(mockFileReader, mockFormat);

        assertNotNull(parser);
        assertSame(mockFormat, getField(parser, "format"));
        assertNotNull(getField(parser, "headerMap"));
    }

    // Helper method to access private fields via reflection
    private Object getField(Object instance, String fieldName) {
        try {
            Field field = instance.getClass().getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.get(instance);
        } catch (Exception e) {
            fail("Reflection error: " + e.getMessage());
            return null;
        }
    }
}
